settings.spec:
{
  "openapi": "3.1.0",
  "info": {
    "title": "GitHub Projects v2 — Move Issue to Status",
    "description": "Dedicated tool to move an issue to a specific status column on a GitHub Projects v2 board via GraphQL mutation.",
    "version": "2.0.0"
  },
  "servers": [
    {
      "url": "https://api.github.com",
      "description": "GitHub REST API base"
    }
  ],
  "paths": {
    "/graphql": {
      "post": {
        "operationId": "moveIssueToStatus",
        "summary": "Move an issue to a specific board status",
        "description": "Moves an issue to a target status column on a GitHub Projects v2 board.\n\nElitea Support Board defaults:\n- projectId: PVT_kwDOECVEvc4BTt9j\n-fieldId: PVTSSF_lADOECVEvc4BTt9jzhA7ANw\n\nStatus name to optionId map: New=3908101e, In Progress=ff02ff19, AI:Human review=e4245cc2, AI: Draft reply=0fbeba05, AI: Communication Approved=6977b7e1, AI: AI Assisted Resolution=0d99496a, Resolved=68aeeb17, To be Checked=622b5399, To be in Release=7b445187, On Hold=df73e18b, Done=98236657",
        "requestBody": {
          "required": true,
          "content": {
            "application/json": {
              "schema": {
                "type": "object",
                "required": ["query", "variables"],
                "properties": {
                  "query": {
                    "type": "string",
                    "description": "GraphQL mutation string"
                  },
                  "variables": {
                    "type": "object",
                    "description": "GraphQL variables",
                    "additionalProperties": true
                  }
                }
              }
            }
          }
        },
        "responses": {
          "200": {
            "description": "GraphQL response",
            "content": {
              "application/json": {
                "schema": {
                  "type": "object",
                  "properties": {
                    "data": {
                      "type": ["object", "null"],
                      "additionalProperties": true
                    },
                    "errors": {
                      "type": "array",
                      "items": {
                        "type": "object",
                        "properties": {
                          "message": { "type": "string" }
                        },
                        "required": ["message"]
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}
